import React, { createContext, useContext, useState, useEffect } from 'react';
import { getMyPermissions } from '../services/api';

const PermissionContext = createContext({ isAdmin: true, can: () => true });

export function PermissionProvider({ children }) {
  const [isAdmin, setIsAdmin] = useState(true);
  const [perms,   setPerms]   = useState(null);

  const load = async () => {
    try {
      const { data } = await getMyPermissions();
      setIsAdmin(!!data.is_admin);
      setPerms(data.is_admin ? null : data);
    } catch {
      setIsAdmin(true); setPerms(null);
    }
  };

  useEffect(() => {
    const token = localStorage.getItem('access') || localStorage.getItem('access_token');
    if (token) load();
  }, []);

  const can = (field) => {
    if (isAdmin) return true;
    if (!perms) return true;
    // Default true if field not set
    return perms[field] !== false && perms[field] !== undefined ? !!perms[field] : true;
  };

  return (
    <PermissionContext.Provider value={{ isAdmin, perms, can, reload: load }}>
      {children}
    </PermissionContext.Provider>
  );
}

export const usePermissions = () => useContext(PermissionContext);
